module shift_register(CLK, RST, LOAD, D, Q);
input CLK, RST, LOAD;
input [7:0] D;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        Q <= 8'b00000000;
    else if (LOAD)
        Q <= D;
    else
        Q <= Q << 1;
end

endmodule
